  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Bitwise-DeFi-Index — Starke Schlagzeile, aber auf einen Token konzentriert</text>
    <g font-family="sans-serif">
      <text x="20" y="62" fill="#a1a1aa" font-size="13" font-weight="700">Rendite im Juni</text>
      <rect x="20" y="75" width="300" height="34" rx="6" fill="#2a1416" stroke="#ef4444" stroke-width="1.5"/>
